/**
 * Node.js wrapper module
 * Provides utility functions for Node.js environment
 */

const path = require('path');
const fs = require('fs');

/**
 * Resolves and validates a file path
 * @param {string} filePath - The file path to resolve
 * @param {string} [basePath=process.cwd()] - The base path for resolution
 * @returns {string} The resolved absolute path
 */
function resolvePath(filePath, basePath = process.cwd()) {
  const resolved = path.resolve(basePath, filePath);

  if (!fs.existsSync(resolved)) {
    throw new Error(`File not found: ${resolved}`);
  }

  return resolved;
}

/**
 * Reads a JSON file and parses its contents
 * @param {string} filePath - Path to the JSON file
 * @returns {Object} The parsed JSON object
 */
function readJsonFile(filePath) {
  const resolvedPath = resolvePath(filePath);
  const content = fs.readFileSync(resolvedPath, 'utf8');
  return JSON.parse(content);
}

/**
 * Safely writes data to a JSON file
 * @param {string} filePath - Path to the output file
 * @param {Object} data - The data to serialize and write
 */
function writeJsonFile(filePath, data) {
  const content = JSON.stringify(data, null, 2);
  fs.writeFileSync(filePath, content, 'utf8');
}

module.exports = {
  resolvePath,
  readJsonFile,
  writeJsonFile
};
